import React from "react";

export default function Forecast() {
  const dailyForecast = Array.from({ length: 16 }, (_, i) => ({
    day: `Day ${i + 1}`,
    condition: i % 2 === 0 ? "☀️ Sunny" : "🌧 Rainy",
    high: `${30 + (i % 5)}°C`,
    low: `${20 + (i % 5)}°C`,
  }));

  return (
    <div className="min-h-screen pt-16 px-4 pb-24 bg-black text-white relative">
      <h1 className="text-3xl font-bold text-center mb-6">16-Day Forecast</h1>
      <div className="space-y-4">
        {dailyForecast.map((forecast, index) => (
          <div
            key={index}
            className="flex items-center justify-between bg-white/10 backdrop-blur-xl rounded-2xl px-6 py-4 shadow-xl ring-1 ring-white/20 border-t border-white/30"
          >
            <div>
              <p className="text-lg font-semibold text-purple-300 drop-shadow-purple">
                {forecast.day}
              </p>
              <p className="text-sm text-white/70 drop-shadow-glow">
                {forecast.condition}
              </p>
            </div>
            <div className="text-right">
              <p className="text-xl font-bold text-purple-400 drop-shadow-purple">
                {forecast.high}
              </p>
              <p className="text-sm text-white/60">Low: {forecast.low}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-black/30 backdrop-blur-md border-t border-white/10 z-10">
        <ul className="flex justify-around py-3">
          {[
            { icon: "🌤", label: "Today" },
            { icon: "☁️", label: "Forecast" },
            { icon: "📡", label: "Radar" },
            { icon: "💬", label: "Community" },
            { icon: "🤖", label: "Chatbot" },
          ].map((tab, idx) => (
            <li
              key={idx}
              className="flex flex-col items-center text-white/80 hover:text-white transition"
            >
              <span className="text-lg">{tab.icon}</span>
              <span className="text-xs mt-1 font-medium">{tab.label}</span>
            </li>
          ))}
        </ul>
      </nav>
    </div>
  );
}
